import{_ as i,W as a,X as e,a1 as t}from"./framework-c9619a7b.js";const n={},o=t('<h2 id="简介" tabindex="-1"><a class="header-anchor" href="#简介" aria-hidden="true">#</a> 简介</h2><p>文件共享即允许计算机之间共享文件和文件夹。Windows提供了简单方便地在局域网内共享文件夹的方式，您可以轻松在多个Windows计算机之间共享文档、音乐、照片等文件。共享文件夹还可以被Mac和Linux计算机访问,只需要知道其IP地址或计算机名即可。</p><h2 id="如何开启共享" tabindex="-1"><a class="header-anchor" href="#如何开启共享" aria-hidden="true">#</a> 如何开启共享</h2><ol><li>新建一个文件夹，名称自定义，我这里取名“共享文件夹测试”</li><li>选中新建的文件夹，右击选择“属性”，切到“共享”选项卡。</li></ol><p>里面提供了<code>简单共享</code>和<code>高级共享</code>两种方式。</p><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230529094556.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><ul><li><p>简单共享</p><blockquote><p>不太推荐使用，会暴露目标文件夹的父级目录内容，不安全，可以参考“高级共享”</p></blockquote><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230529094922.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230529095007.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230529095039.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>成功，可以在局域网其他设备上测试连接。</p></li><li><p>高级共享</p><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230529095908.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>进行用户添加和权限设置</p><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230529095812.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>启用共享</p><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230529100037.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>局域网其他设备连接测试：</p><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230529100208.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>成功！</p></li></ul><h2 id="如何关闭共享" tabindex="-1"><a class="header-anchor" href="#如何关闭共享" aria-hidden="true">#</a> 如何关闭共享</h2><p>打开计算机管理，找到“共享文件夹”，在“共享”下找到目标共享名，右击选择“停止共享”。</p><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230529095512.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure>',10),g=[o];function l(p,d){return a(),e("div",null,g)}const r=i(n,[["render",l],["__file","Windows文件共享教程.html.vue"]]);export{r as default};
